class Solution:
    def equalFrequency(self, word: str) -> bool:
        from collections import Counter
        n = len(word)
        for i in range(n):
            new_word = word[:i] + word[i+1:]
            freq = Counter(new_word).values()
            if len(set(freq)) == 1:
                return True
        return False
